```typescript
user: {
  modelName: "users",           // Customize table name
  fields: {
    email: "emailAddress",      // Map "email" to different column
    name: "fullName"            // Map "name" to different column
  },
  additionalFields: {
    customField: {
      type: "string",
    }
  },
  changeEmail: { /* ... */ },
  deleteUser: { /* ... */ }
}
```

